from agent import *from models.products import *def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.sessionbreakers = [SessionBreak(max_requests=8000)]    session.queue(Request('https://www.dkamera.de/testbericht/#tab-alle'), process_revlist, dict())def process_revlist(data, context, session):    strip_namespace(data)    revs = data.xpath('//table[@id="tkl_testbericht_uebersicht"]//tbody/tr')    for rev in revs:        name = rev.xpath('td[contains(@class, "camera")]/a//text()[normalize-space()]').string(multiple=True)        manufacturer = rev.xpath('td[contains(@class, "camera")]/a/strong/text()').string()        url = rev.xpath('td[contains(@class, "camera")]/a/@href').string()        prod_url = rev.xpath('td[@class="price"]/a/@href').string()        grade_overall = rev.xpath('td[@class="score"]/text()').string()        if name and url:            session.queue(Request(url), process_review, dict(name=name, manufacturer=manufacturer, url=url, prod_url=prod_url, grade_overall=grade_overall))    # Load all revsdef process_review(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.url = context['prod_url'] or context['url']    product.category = "Digitalkameras"    product.ssid = context['url'].strip('/').split('/')[-1]    product.manufacturer = context.get('manufacturer')    review = Review()    review.title = data.xpath('//h1[@id="title"]/a//text()').string()    review.url = context['url']    review.type = 'pro'    review.ssid = product.ssid    date = data.xpath('//div[contains(@id, "node-")]/span/text()').string()    if date:        review.date = date.split()[0]    grade_overall = context.get('grade_overall')    if grade_overall:        grade_overall = grade_overall.strip(' %').replace(',', '.')        if grade_overall and grade_overall.split('.')[0].isdigit():            review.grades.append(Grade(type='overall', value=float(grade_overall), best=100.0))    excerpt = data.xpath('//div[contains(@class, "testbericht")]/div[contains(@class, "node")]/p[not(@class="teaser-images")][not(preceding::h3[contains(., "Testurteil")])][not(regexp:test(., "Unser Fazit:", "i"))][not(preceding::p[regexp:test(., "Unser Fazit:", "i")])]//text()[normalize-space()]').string(multiple=True)    if excerpt and excerpt.strip():        context['excerpt'] = excerpt    next_url = data.xpath('//a[@class="next-page"][not(regexp:test(., "Zur Übersicht", "i"))]/@href').string()    if next_url:        page = 1        title = data.xpath('//select[@class="select-page"]/option[@selected]/text()').string()        review.add_property(type='pages', value=dict(title=title, url=review.url))        session.do(Request(next_url), process_review_next, dict(context, product=product, review=review, page=page+1))    else:        context['product'] = product        context['review'] = review        process_review_next(data, context, session)def process_review_next(data, context, session):    strip_namespace(data)    product = context['product']    review = context['review']    conclusion = data.xpath('//div[contains(@class, "testbericht")]/div[contains(@class, "node")]/p[not(@class="teaser-images")][not(preceding::h3[contains(., "Testurteil")])][regexp:test(., "Unser Fazit:", "i") or preceding::*[regexp:test(., "Unser Fazit:", "i")]]//text()[normalize-space()]').string(multiple=True)    if conclusion and conclusion.strip():        conclusion = conclusion.replace('Unser Fazit:', '').strip()    page = context.get('page', 1)    if page > 1:        title = data.xpath('//select[@class="select-page"]/option[@selected]/text()').string()        review.add_property(type='pages', value=dict(title=title, url=data.response_url))        excerpt = data.xpath('//div[contains(@class, "testbericht")]/div[contains(@class, "node")]/p[not(@class="teaser-images")][not(preceding::h3[contains(., "Testurteil")])][not(regexp:test(., "Unser Fazit:", "i"))][not(preceding::*[regexp:test(., "Unser Fazit:", "i")])]//text()[normalize-space()]').string(multiple=True)        if excerpt and not conclusion and 'fazit' in title.lower():            conclusion = excerpt.strip()        elif excerpt and excerpt.strip():            context['excerpt'] = context.get('excerpt', '') + " " + excerpt.strip()    pros = data.xpath('//ul[@class="pro"]/li/text()[normalize-space()]').strings()    for pro in pros:        pro = pro.strip('*+.-_\n ')        if pro:            review.add_property(type='pros', value=pro)    cons = data.xpath('//ul[@class="contra"]/li/text()[normalize-space()]').strings()    for con in cons:        con = con.strip('*+.-_\n ')        if con:            review.add_property(type='cons', value=con)    if conclusion:        review.add_property(type='conclusion', value=conclusion)    next_url = data.xpath('//a[@class="next-page"][not(regexp:test(., "Zur Übersicht", "i"))]/@href').string()    if next_url:        session.do(Request(next_url), process_review_next, dict(context, page=page+1))    elif context.get('excerpt'):        review.add_property(type="excerpt", value=context['excerpt'].strip())        product.reviews.append(review)        session.emit(product)